prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?defs ?choreo ?choreoName ?taskCount ?eventCount ?gatewayCount WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    ?task a bboExt:ChoreographyTask .
    ?task tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?event a ?eventType .
    ?event tai:belongsTo ?choreo .
    FILTER(?eventType IN (bboExt:StartEvent, bboExt:EndEvent, bboExt:IntermediateCatchEvent))
  }
  OPTIONAL {
    ?gateway a ?gatewayType .
    ?gateway tai:belongsTo ?choreo .
    FILTER(?gatewayType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  }
}
GROUP BY ?defs ?choreo ?choreoName
ORDER BY DESC(?taskCount)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName 
       (COUNT(DISTINCT ?task) AS ?taskCount) 
       (COUNT(DISTINCT ?event) AS ?eventCount) 
       (COUNT(DISTINCT ?gateway) AS ?gatewayCount)
       (COUNT(DISTINCT ?seqFlow) AS ?seqFlowCount)
       (COUNT(DISTINCT ?msgFlow) AS ?msgFlowCount)
WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL {
    ?task a bboExt:ChoreographyTask .
    ?task tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?event a ?eventType .
    ?event tai:belongsTo ?choreo .
    FILTER(?eventType IN (bboExt:StartEvent, bboExt:EndEvent, bboExt:IntermediateCatchEvent))
  }
  OPTIONAL {
    ?gateway a ?gatewayType .
    ?gateway tai:belongsTo ?choreo .
    FILTER(?gatewayType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  }
  OPTIONAL {
    ?seqFlow a bbo:SequenceFlow .
    ?seqFlow tai:belongsTo ?choreo .
  }
  OPTIONAL {
    ?msgFlow a bboExt:MessageFlow .
    ?msgFlow tai:belongsTo ?choreo .
  }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?taskCount)
LIMIT 25
